/**
 * Segment Tree implementation for Range Maximum Query (RMQ)
 * Used here to store and query the maximum DP scores associated with specific values.
 * The segment tree operates on values V in the range [1, V_MAX].
 */
class SegmentTree {
    constructor(size) {
        this.size = size;
        // Tree size: 4 * size is usually safe
        this.tree = new Array(4 * size + 1).fill(-1);
    }

    // Internal recursive update function
    // nodeIdx: current node in the segment tree
    // start, end: range covered by the current node
    // idx: the value index being updated (1 <= idx <= size)
    // val: the new maximum score to potentially store
    _update(nodeIdx, start, end, idx, val) {
        if (start === end) {
            // Leaf node reached. Update with the maximum score seen for this value.
            this.tree[nodeIdx] = Math.max(this.tree[nodeIdx], val);
            return;
        }

        const mid = Math.floor((start + end) / 2);
        if (idx <= mid) {
            // Go left
            this._update(2 * nodeIdx, start, mid, idx, val);
        } else {
            // Go right
            this._update(2 * nodeIdx + 1, mid + 1, end, idx, val);
        }

        // Update current node based on children
        this.tree[nodeIdx] = Math.max(this.tree[2 * nodeIdx], this.tree[2 * nodeIdx + 1]);
    }

    // Public update method: updates the maximum score for a specific value 'idx'
    update(idx, val) {
        if (idx < 1 || idx > this.size) return;
        this._update(1, 1, this.size, idx, val);
    }

    // Internal recursive query function
    // nodeIdx: current node
    // start, end: range covered by current node
    // l, r: query range [l, r]
    _query(nodeIdx, start, end, l, r) {
        if (r < start || end < l || l > r) {
            // Range outside query scope
            return -1; // Return -1 to represent 'no score found' or zero if scores start at 0
        }

        if (l <= start && end <= r) {
            // Current node range is completely within query range
            return this.tree[nodeIdx];
        }

        const mid = Math.floor((start + end) / 2);

        const p1 = this._query(2 * nodeIdx, start, mid, l, r);
        const p2 = this._query(2 * nodeIdx + 1, mid + 1, end, l, r);

        return Math.max(p1, p2);
    }

    // Public query method: returns the maximum score in the value range [l, r]
    query(l, r) {
        if (l > r || l < 1 || r > this.size) return -1;
        return this._query(1, 1, this.size, l, r);
    }
}


function solve(nums, k) {
    const N = nums.length;
    const V_MAX = 100000; // Maximum possible value of nums[i]

    // DP arrays: DP[i] stores the max score ending at index i
    // UP[i]: nums[i] > nums[j] (ending with an upward swing)
    // DOWN[i]: nums[i] < nums[j] (ending with a downward swing)
    const UP = new Array(N).fill(0);
    const DOWN = new Array(N).fill(0);

    // Segment Trees indexed by value [1, V_MAX]
    // ST_UP stores max(UP[j]) for a given value nums[j]
    const ST_UP = new SegmentTree(V_MAX);
    // ST_DOWN stores max(DOWN[j]) for a given value nums[j]
    const ST_DOWN = new SegmentTree(V_MAX);

    // Updates queue/scheduler: Stores {value, up_score, down_score} ready to be inserted 
    // into STs at index 'ready_time'.
    // Since k >= 1, the ready time index will be at least 1. Max ready time is N-1 + K.
    const ready_time = N + k;
    const updates = new Array(ready_time + 1).fill(null).map(() => []);

    let max_total_score = 0;

    for (let i = 0; i < N; i++) {
        const val_i = nums[i];

        // 1. Process scheduled updates that become ready at time i
        for (const update_item of updates[i]) {
            const v = update_item.value;
            const up_score = update_item.up_score;
            const down_score = update_item.down_score;

            // Update STs using the calculated scores from the previous index j
            ST_UP.update(v, up_score);
            ST_DOWN.update(v, down_score);
        }

        // 2. Calculate UP[i]: requires transition from a sequence ending in a DOWN swing (j < i-k, nums[j] < nums[i])

        // Query ST_DOWN for max score where value < val_i (i.e., range [1, val_i - 1])
        let M_down = ST_DOWN.query(1, val_i - 1);

        // Base case: length 1 sequence (score = val_i). M_down = -1 if no previous element satisfies conditions.
        // If M_down is -1, we use 0 as the precursor score.
        const prev_score_down = Math.max(0, M_down);
        UP[i] = val_i + prev_score_down;

        // 3. Calculate DOWN[i]: requires transition from a sequence ending in an UP swing (j < i-k, nums[j] > nums[i])

        // Query ST_UP for max score where value > val_i (i.e., range [val_i + 1, V_MAX])
        let M_up = ST_UP.query(val_i + 1, V_MAX);

        // Base case: length 1 sequence.
        const prev_score_up = Math.max(0, M_up);
        DOWN[i] = val_i + prev_score_up;

        // Update overall maximum score
        max_total_score = Math.max(max_total_score, UP[i], DOWN[i]);

        // 4. Schedule current results for future indices (i+k, i+2k, ...)
        const ready_time_i = i + k;
        if (ready_time_i <= N - 1) {
            updates[ready_time_i].push({
                value: val_i,
                up_score: UP[i],
                down_score: DOWN[i]
            });
        }
    }

    // Edge case: if N=1, the loop calculates max_total_score = nums[0], which is correct.
    // If N=0, constraints prevent this.

    return max_total_score;
}

